1	export type Cell = [number, number];
2	
3	const isSameCell = ([x, y]: Cell, [otherX, otherY]: Cell): boolean =>
4	  x === otherX && y === otherY;
5	
6	const containsCell = (cells: Cell[], cell: Cell): boolean =>
7	  cells.some((other) => isSameCell(other, cell));
8	
9	const NEIGHBOR_OFFSETS: Cell[] = [
10	  [-1, -1], [-1, 0], [-1, 1],
11	  [0, -1], [0, 1],
12	  [1, -1], [1, 0], [1, 1],
13	];
14	
15	const neighborsOf = ([x, y]: Cell): Cell[] =>
16	  NEIGHBOR_OFFSETS.map(([dx, dy]): Cell => [x + dx, y + dy]);
17	
18	const deduplicate = (cells: Cell[]): Cell[] =>
19	  cells.filter((cell, index) => !containsCell(cells.slice(0, index), cell));
20	
21	const countLiveNeighbors = (cell: Cell, liveCells: Cell[]): number =>
22	  neighborsOf(cell).filter((neighbor) => containsCell(liveCells, neighbor))
23	    .length;
24	
25	const survives = (cell: Cell, liveCells: Cell[]): boolean => {
26	  const liveNeighbors = countLiveNeighbors(cell, liveCells);
27	  return liveNeighbors === 2 || liveNeighbors === 3;
28	};
29	
30	const isBorn = (cell: Cell, liveCells: Cell[]): boolean =>
31	  !containsCell(liveCells, cell) && countLiveNeighbors(cell, liveCells) === 3;
32	
33	export const nextGeneration = (liveCells: Cell[]): Cell[] => {
34	  const survivors = liveCells.filter((cell) => survives(cell, liveCells));
35	  const births = deduplicate(liveCells.flatMap(neighborsOf)).filter((cell) =>
36	    isBorn(cell, liveCells),
37	  );
38	  return [...survivors, ...births];
39	};
